    // ---- Bulk Import Processing ----

    private BulkImportResult processBulkImport(Document dataDocument, ImportJob job) {
        BulkImportResult result = new BulkImportResult(job.getJobId());
        job.setStatus("PROCESSING");

        Element root = dataDocument.getDocumentElement();
        String batchTag = job.getConfig().getBatchElementName();
        String recordTag = job.getConfig().getRecordElementName();

        NodeList batchNodes;
        if (batchTag != null && !batchTag.isEmpty()) {
            batchNodes = root.getElementsByTagName(batchTag);
        } else {
            // Treat root as single batch
            batchNodes = root.getChildNodes();
        }

        int totalRecords = 0;
        int successCount = 0;
        int errorCount = 0;

        // Process in batches
        NodeList recordNodes = root.getElementsByTagName(recordTag);
        int batchSize = job.getConfig().getBatchSize();
        int totalBatches = (int) Math.ceil((double) recordNodes.getLength() / batchSize);

        LOGGER.info("Processing " + recordNodes.getLength() + " records in " + totalBatches + " batches");

        for (int batchNum = 0; batchNum < totalBatches; batchNum++) {
            int start = batchNum * batchSize;
            int end = Math.min(start + batchSize, recordNodes.getLength());

            job.setCurrentBatch(batchNum + 1);
            job.setTotalBatches(totalBatches);

            for (int i = start; i < end; i++) {
                totalRecords++;
                Element recordElement = (Element) recordNodes.item(i);

                try {
                    Map<String, String> recordData = extractRecordData(recordElement, job.getConfig());

                    // Apply field mappings
                    Map<String, String> mappedData = applyFieldMappings(recordData, job.getConfig().getFieldMappings());

                    // Apply transformations
                    Map<String, String> transformedData = applyTransformations(mappedData, job.getConfig().getTransformations());

                    // Validate
                    List<String> validationErrors = validateRecord(transformedData, job.getConfig().getValidationRules());
                    if (!validationErrors.isEmpty()) {
                        errorCount++;
                        result.addRecordError(i, validationErrors);
                        if (job.getConfig().isStopOnError()) {
                            job.setStatus("STOPPED");
                            break;
                        }
                        continue;
                    }

                    // Store
                    dataStore.store(job.getConfig().getTargetEntity(), transformedData);
                    successCount++;
                } catch (Exception e) {
                    errorCount++;
                    result.addRecordError(i, Collections.singletonList(e.getMessage()));
                    if (job.getConfig().isStopOnError()) {
                        job.setStatus("STOPPED");
                        break;
                    }
                }
            }

            job.setProcessedRecords(totalRecords);
            LOGGER.info("Batch " + (batchNum + 1) + "/" + totalBatches + " complete. Success: " + successCount + ", Errors: " + errorCount);

            if ("STOPPED".equals(job.getStatus())) {
                break;
            }
        }

        result.setTotalRecords(totalRecords);
        result.setSuccessCount(successCount);
        result.setErrorCount(errorCount);

        job.setStatus("STOPPED".equals(job.getStatus()) ? "STOPPED" : "COMPLETED");
        job.setProcessedRecords(totalRecords);

        return result;
    }

    private Map<String, String> extractRecordData(Element recordElement, ImportConfiguration config) {
        Map<String, String> data = new LinkedHashMap<>();

        // Extract attributes
        NamedNodeMap attributes = recordElement.getAttributes();
        if (attributes != null) {
            for (int i = 0; i < attributes.getLength(); i++) {
                Node attr = attributes.item(i);
                data.put("@" + attr.getNodeName(), attr.getNodeValue());
            }
        }

        // Extract child elements recursively
        extractChildElements(recordElement, "", data, config.getMaxDepth());

        return data;
    }

    private void extractChildElements(Element parent, String prefix, Map<String, String> data, int maxDepth) {
        if (maxDepth <= 0) return;

        NodeList children = parent.getChildNodes();
        Map<String, Integer> elementCounts = new HashMap<>();

        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;
                String tagName = childElement.getTagName();

                int count = elementCounts.getOrDefault(tagName, 0);
                elementCounts.put(tagName, count + 1);

                String key = prefix.isEmpty() ? tagName : prefix + "." + tagName;
                if (count > 0) {
                    key = key + "[" + count + "]";
                }

                // Extract attributes
                NamedNodeMap attrs = childElement.getAttributes();
                if (attrs != null) {
                    for (int j = 0; j < attrs.getLength(); j++) {
                        Node attr = attrs.item(j);
                        data.put(key + ".@" + attr.getNodeName(), attr.getNodeValue());
                    }
                }

                // Check if leaf node
                if (isLeafElement(childElement)) {
                    data.put(key, childElement.getTextContent().trim());
                } else {
                    // Recurse into nested elements
                    extractChildElements(childElement, key, data, maxDepth - 1);
                }
            }
        }
    }

    private boolean isLeafElement(Element element) {
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return false;
            }
        }
        return true;
    }

    // ---- Configuration Parsing ----

    private ImportConfiguration parseImportConfiguration(Document configDocument) {
        ImportConfiguration config = new ImportConfiguration();
        Element root = configDocument.getDocumentElement();

        config.setTargetEntity(getElementText(root, "TargetEntity"));
        config.setRecordElementName(getElementText(root, "RecordElementName"));
        config.setBatchElementName(getElementText(root, "BatchElementName"));

        String batchSizeStr = getElementText(root, "BatchSize");
        config.setBatchSize(batchSizeStr.isEmpty() ? 100 : Integer.parseInt(batchSizeStr));

        String maxDepthStr = getElementText(root, "MaxDepth");
        config.setMaxDepth(maxDepthStr.isEmpty() ? 10 : Integer.parseInt(maxDepthStr));

        config.setStopOnError("true".equalsIgnoreCase(getElementText(root, "StopOnError")));

        // Parse field mappings
        NodeList mappingNodes = root.getElementsByTagName("FieldMapping");
        Map<String, String> fieldMappings = new LinkedHashMap<>();
        for (int i = 0; i < mappingNodes.getLength(); i++) {
            Element mapping = (Element) mappingNodes.item(i);
            String source = mapping.getAttribute("source");
            String target = mapping.getAttribute("target");
            if (!source.isEmpty() && !target.isEmpty()) {
                fieldMappings.put(source, target);
            }
        }
        config.setFieldMappings(fieldMappings);

        // Parse transformations
        NodeList transformNodes = root.getElementsByTagName("Transformation");
        Map<String, String> transformations = new LinkedHashMap<>();
        for (int i = 0; i < transformNodes.getLength(); i++) {
            Element transform = (Element) transformNodes.item(i);
            String field = transform.getAttribute("field");
            String type = transform.getAttribute("type");
            if (!field.isEmpty() && !type.isEmpty()) {
                transformations.put(field, type);
            }
        }
        config.setTransformations(transformations);

        // Parse validation rules
        NodeList validationNodes = root.getElementsByTagName("ValidationRule");
        Map<String, String> validationRules = new LinkedHashMap<>();
        for (int i = 0; i < validationNodes.getLength(); i++) {
            Element validation = (Element) validationNodes.item(i);
            String field = validation.getAttribute("field");
            String rule = validation.getAttribute("rule");
            if (!field.isEmpty() && !rule.isEmpty()) {
                validationRules.put(field, rule);
            }
        }
        config.setValidationRules(validationRules);

        return config;
    }

    private QueryRequest parseQueryRequest(Document queryDocument) {
        QueryRequest request = new QueryRequest();
        Element root = queryDocument.getDocumentElement();

        request.setEntityType(getElementText(root, "EntityType"));
        request.setMaxResults(getElementText(root, "MaxResults").isEmpty() ? 100 :
                Integer.parseInt(getElementText(root, "MaxResults")));

        // Parse filter conditions
        NodeList filterNodes = root.getElementsByTagName("Filter");
        for (int i = 0; i < filterNodes.getLength(); i++) {
            Element filter = (Element) filterNodes.item(i);
            String field = filter.getAttribute("field");
            String operator = filter.getAttribute("operator");
            String value = filter.getTextContent().trim();
            request.addFilter(field, operator, value);
        }

        return request;
    }

    // ---- Data Transformation & Validation ----

    private Map<String, String> applyFieldMappings(Map<String, String> data, Map<String, String> mappings) {
        if (mappings == null || mappings.isEmpty()) return data;

        Map<String, String> mappedData = new LinkedHashMap<>();
        for (Map.Entry<String, String> entry : data.entrySet()) {
            String targetField = mappings.getOrDefault(entry.getKey(), entry.getKey());
            mappedData.put(targetField, entry.getValue());
        }
        return mappedData;
    }

    private Map<String, String> applyTransformations(Map<String, String> data, Map<String, String> transformations) {
        if (transformations == null || transformations.isEmpty()) return data;

        Map<String, String> transformed = new LinkedHashMap<>(data);
        for (Map.Entry<String, String> transform : transformations.entrySet()) {
            String field = transform.getKey();
            String type = transform.getValue();
            if (transformed.containsKey(field)) {
                String value = transformed.get(field);
                switch (type.toLowerCase()) {
                    case "uppercase":
                        transformed.put(field, value.toUpperCase());
                        break;
                    case "lowercase":
                        transformed.put(field, value.toLowerCase());
                        break;
                    case "trim":
                        transformed.put(field, value.trim());
                        break;
                    case "strip_whitespace":
                        transformed.put(field, value.replaceAll("\\s+", ""));
                        break;
                    default:
                        break;
                }
            }
        }
        return transformed;
    }

    private List<String> validateRecord(Map<String, String> data, Map<String, String> rules) {
        List<String> errors = new ArrayList<>();
        if (rules == null || rules.isEmpty()) return errors;

        for (Map.Entry<String, String> rule : rules.entrySet()) {
            String field = rule.getKey();
            String ruleType = rule.getValue();
            String value = data.get(field);

            switch (ruleType.toLowerCase()) {
                case "required":
                    if (value == null || value.trim().isEmpty()) {
                        errors.add("Field '" + field + "' is required");
                    }
                    break;
                case "numeric":
                    if (value != null && !value.isEmpty()) {
                        try {
                            Double.parseDouble(value);
                        } catch (NumberFormatException e) {
                            errors.add("Field '" + field + "' must be numeric");
                        }
                    }
                    break;
                case "email":
                    if (value != null && !value.isEmpty() && !value.matches("^[\\w.-]+@[\\w.-]+\\.\\w+$")) {
                        errors.add("Field '" + field + "' must be a valid email");
                    }
                    break;
                default:
                    break;
            }
        }
        return errors;
    }

    // ---- Utility Methods ----

    private String getElementText(Element parent, String tagName) {
        NodeList nodes = parent.getElementsByTagName(tagName);
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent().trim();
        }
        return "";
    }

    private void processCustomAttributes(Element parent, Map<String, String> data, String prefix) {
        NodeList attrNodes = parent.getElementsByTagName("CustomAttribute");
        for (int i = 0; i < attrNodes.getLength(); i++) {
            Element attrElement = (Element) attrNodes.item(i);
            String attrName = attrElement.getAttribute("name");
            String attrValue = attrElement.getTextContent().trim();
            data.put(prefix + "custom_" + attrName, attrValue);
        }
    }

    private void processNestedCategories(Element parent, Map<String, String> data, String prefix) {
        NodeList catNodes = parent.getElementsByTagName("CategoryHierarchy");
        if (catNodes.getLength() > 0) {
            Element catHierarchy = (Element) catNodes.item(0);
            List<String> categoryPath = new ArrayList<>();
            buildCategoryPath(catHierarchy, categoryPath);
            data.put(prefix + "categoryPath", String.join(" > ", categoryPath));
        }
    }

    private void buildCategoryPath(Element element, List<String> path) {
        NodeList catNodes = element.getChildNodes();
        for (int i = 0; i < catNodes.getLength(); i++) {
            Node child = catNodes.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE && "Category".equals(child.getNodeName())) {
                Element catElement = (Element) child;
                String name = catElement.getAttribute("name");
                if (!name.isEmpty()) {
                    path.add(name);
                }
                buildCategoryPath(catElement, path);
            }
        }
    }

    private void flattenElement(Element element, String prefix, Map<String, String> currentRecord,
                                List<Map<String, String>> records, int depth) {
        if (depth > 20) return; // Prevent infinite recursion

        String key = prefix.isEmpty() ? element.getTagName() : prefix + "." + element.getTagName();

        // Add attributes
        NamedNodeMap attrs = element.getAttributes();
        if (attrs != null) {
            for (int i = 0; i < attrs.getLength(); i++) {
                Node attr = attrs.item(i);
                currentRecord.put(key + ".@" + attr.getNodeName(), attr.getNodeValue());
            }
        }

        if (isLeafElement(element)) {
            currentRecord.put(key, element.getTextContent().trim());
        } else {
            NodeList children = element.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                Node child = children.item(i);
                if (child.getNodeType() == Node.ELEMENT_NODE) {
                    flattenElement((Element) child, key, currentRecord, records, depth + 1);
                }
            }
        }

        if (depth == 1) {
            records.add(new LinkedHashMap<>(currentRecord));
            currentRecord.clear();
        }
    }

    // ---- XML Response Building ----

    private String buildResponseXml(ProcessingResult result) {
        StringBuilder sb = new StringBuilder();
        sb.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
        sb.append("<ProcessingResponse>");
        sb.append("<RequestId>").append(escapeXml(result.getRequestId())).append("</RequestId>");
        sb.append("<Status>").append(result.getErrors().isEmpty() ? "SUCCESS" : "PARTIAL").append("</Status>");
        sb.append("<TotalProcessed>").append(result.getSuccesses().size() + result.getErrors().size()).append("</TotalProcessed>");
        sb.append("<SuccessCount>").append(result.getSuccesses().size()).append("</SuccessCount>");
        sb.append("<ErrorCount>").append(result.getErrors().size()).append("</ErrorCount>");

        if (!result.getSuccesses().isEmpty()) {
            sb.append("<Successes>");
            for (String success : result.getSuccesses()) {
                sb.append("<Item>").append(escapeXml(success)).append("</Item>");
            }
            sb.append("</Successes>");
        }

        if (!result.getErrors().isEmpty()) {
            sb.append("<Errors>");
            for (String error : result.getErrors()) {
                sb.append("<Error>").append(escapeXml(error)).append("</Error>");
            }
            sb.append("</Errors>");
        }

        sb.append("</ProcessingResponse>");
        return sb.toString();
    }

    private String buildBulkImportResponseXml(BulkImportResult result) {
        StringBuilder sb = new StringBuilder();
        sb.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
        sb.append("<BulkImportResponse>");
        sb.append("<JobId>").append(escapeXml(result.getJobId())).append("</JobId>");
        sb.append("<Status>").append(result.getErrorCount() == 0 ? "SUCCESS" : "COMPLETED_WITH_ERRORS").append("</Status>");
        sb.append("<TotalRecords>").append(result.getTotalRecords()).append("</TotalRecords>");
        sb.append("<SuccessCount>").append(result.getSuccessCount()).append("</SuccessCount>");
        sb.append("<ErrorCount>").append(result.getErrorCount()).append("</ErrorCount>");

        if (!result.getRecordErrors().isEmpty()) {
            sb.append("<RecordErrors>");
            for (Map.Entry<Integer, List<String>> entry : result.getRecordErrors().entrySet()) {
                sb.append("<RecordError index=\"").append(entry.getKey()).append("\">");
                for (String error : entry.getValue()) {
                    sb.append("<Error>").append(escapeXml(error)).append("</Error>");
                }
                sb.append("</RecordError>");
            }
            sb.append("</RecordErrors>");
        }

        sb.append("</BulkImportResponse>");
        return sb.toString();
    }

    private String buildQueryResponseXml(String requestId, List<Map<String, String>> results) {
        StringBuilder sb = new StringBuilder();
        sb.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
        sb.append("<QueryResponse>");
        sb.append("<RequestId>").append(escapeXml(requestId)).append("</RequestId>");
        sb.append("<ResultCount>").append(results.size()).append("</ResultCount>");
        sb.append("<Results>");

        for (Map<String, String> record : results) {
            sb.append("<Record>");
            for (Map.Entry<String, String> field : record.entrySet()) {
                sb.append("<Field name=\"").append(escapeXml(field.getKey())).append("\">")
                        .append(escapeXml(field.getValue())).append("</Field>");
            }
            sb.append("</Record>");
        }

        sb.append("</Results>");
        sb.append("</QueryResponse>");
        return sb.toString();
    }

    private String buildStatusResponseXml(ImportJob job) {
        StringBuilder sb = new StringBuilder();
        sb.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
        sb.append("<ImportStatusResponse>");
        sb.append("<JobId>").append(escapeXml(job.getJobId())).append("</JobId>");
        sb.append("<Status>").append(escapeXml(job.getStatus())).append("</Status>");
        sb.append("<CurrentBatch>").append(job.getCurrentBatch()).append("</CurrentBatch>");
        sb.append("<TotalBatches>").append(job.getTotalBatches()).append("</TotalBatches>");
        sb.append("<ProcessedRecords>").append(job.getProcessedRecords()).append("</ProcessedRecords>");
        sb.append("</ImportStatusResponse>");
        return sb.toString();
    }

    private String buildErrorResponseXml(String requestId, String errorMessage) {
        StringBuilder sb = new StringBuilder();
        sb.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
        sb.append("<ErrorResponse>");
        sb.append("<RequestId>").append(escapeXml(requestId)).append("</RequestId>");
        sb.append("<Status>ERROR</Status>");
        sb.append("<ErrorMessage>").append(escapeXml(errorMessage)).append("</ErrorMessage>");
        sb.append("</ErrorResponse>");
        return sb.toString();
    }

    private String escapeXml(String value) {
        if (value == null) return "";
        return value.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&apos;");
    }

