    static class QueryRequest {
        private String entityType;
        private int maxResults = 100;
        private final List<FilterCondition> filters = new ArrayList<>();

        String getEntityType() { return entityType; }
        void setEntityType(String entityType) { this.entityType = entityType; }
        int getMaxResults() { return maxResults; }
        void setMaxResults(int maxResults) { this.maxResults = maxResults; }
        List<FilterCondition> getFilters() { return filters; }

        void addFilter(String field, String operator, String value) {
            filters.add(new FilterCondition(field, operator, value));
        }
    }

    static class FilterCondition {
        private final String field;
        private final String operator;
        private final String value;

        FilterCondition(String field, String operator, String value) {
            this.field = field;
            this.operator = operator;
            this.value = value;
        }

        String getField() { return field; }
        String getOperator() { return operator; }
        String getValue() { return value; }
    }

    static class DataStore {
        private final ConcurrentHashMap<String, List<Map<String, String>>> store = new ConcurrentHashMap<>();

        void store(String entityType, Map<String, String> data) {
            store.computeIfAbsent(entityType, k -> Collections.synchronizedList(new ArrayList<>())).add(new LinkedHashMap<>(data));
        }

        List<Map<String, String>> query(QueryRequest request) {
            List<Map<String, String>> entities = store.getOrDefault(request.getEntityType(), Collections.emptyList());
            List<Map<String, String>> results = new ArrayList<>();

            for (Map<String, String> record : entities) {
                if (matchesFilters(record, request.getFilters())) {
                    results.add(record);
                    if (results.size() >= request.getMaxResults()) break;
                }
            }

            return results;
        }

        private boolean matchesFilters(Map<String, String> record, List<FilterCondition> filters) {
            for (FilterCondition filter : filters) {
                String fieldValue = record.get(filter.getField());
                if (fieldValue == null) return false;

                switch (filter.getOperator().toLowerCase()) {
                    case "equals":
                    case "eq":
                        if (!fieldValue.equals(filter.getValue())) return false;
                        break;
                    case "contains":
                        if (!fieldValue.contains(filter.getValue())) return false;
                        break;
                    case "startswith":
                        if (!fieldValue.startsWith(filter.getValue())) return false;
                        break;
                    case "endswith":
                        if (!fieldValue.endsWith(filter.getValue())) return false;
                        break;
                    case "gt":
                        try {
                            if (Double.parseDouble(fieldValue) <= Double.parseDouble(filter.getValue())) return false;
                        } catch (NumberFormatException e) { return false; }
                        break;
                    case "lt":
                        try {
                            if (Double.parseDouble(fieldValue) >= Double.parseDouble(filter.getValue())) return false;
                        } catch (NumberFormatException e) { return false; }
                        break;
                    case "neq":
                    case "notequals":
                        if (fieldValue.equals(filter.getValue())) return false;
                        break;
                    default:
                        break;
                }
            }
            return true;
        }

        int getEntityCount(String entityType) {
            List<Map<String, String>> entities = store.get(entityType);
            return entities == null ? 0 : entities.size();
        }
    }

    static class XmlErrorHandler implements org.xml.sax.ErrorHandler {
        private static final Logger LOGGER = Logger.getLogger(XmlErrorHandler.class.getName());

        @Override
        public void warning(org.xml.sax.SAXParseException exception) {
            LOGGER.warning("XML Parse Warning: " + exception.getMessage());
        }

        @Override
        public void error(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.severe("XML Parse Error: " + exception.getMessage());
            throw exception;
        }

        @Override
        public void fatalError(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.severe("XML Parse Fatal Error: " + exception.getMessage());
            throw exception;
        }
    }

