    public static void main(String[] args) {
        // Publish the SOAP service endpoint
        String serviceUrl = "http://localhost:8080/enterprise/dataintegration";
        EnterpriseDataIntegrationService service = new EnterpriseDataIntegrationService();

        try {
            Endpoint endpoint = Endpoint.publish(serviceUrl, service);
            System.out.println("Enterprise Data Integration SOAP Service started at: " + serviceUrl);
            System.out.println("WSDL available at: " + serviceUrl + "?wsdl");

            // Run demo tests
            runDemoTests(service);

            System.out.println("\nService is running. Press Enter to stop...");
            System.in.read();

            endpoint.stop();
            System.out.println("Service stopped.");
        } catch (Exception e) {
            System.err.println("Failed to start service: " + e.getMessage());
            e.printStackTrace();

            // Still run demo tests even if endpoint fails
            System.out.println("\nRunning demo tests directly...\n");
            runDemoTests(service);
        }
    }

